import{E as e,H as t,c as n,dt as r,f as i,lt as a}from"./_plugin-vue_export-helper-DcdGuE-v.js";import{a as o}from"./index-D_J02O5D.js";var s=JSON.parse(`[{"id":"fior-di-panna","nome":"Fior di Panna","categoria":"crema","payoff":"La base classica delle gelaterie italiane. Latte, panna, pochissimo.","ingredienti":[{"id":"latte-intero","g_per_kg":600},{"id":"panna-35","g_per_kg":150},{"id":"saccarosio","g_per_kg":160},{"id":"latte-polvere-scremato","g_per_kg":50},{"id":"glucosio-42de","g_per_kg":30},{"id":"stabilizzante","g_per_kg":8}],"ingredientiModificabili":[{"nome":"Panna 35%","min":80,"max":250},{"nome":"Saccarosio","min":120,"max":210},{"nome":"Sciroppo di glucosio 42DE","min":0,"max":70}],"procedimento":["Pesare tutti gli ingredienti.","Sciogliere il latte in polvere scremato nel latte intero a temperatura ambiente, mescolando con frusta.","Aggiungere saccarosio e sciroppo di glucosio; disperdere lo stabilizzante in una piccola quantità di saccarosio e unire al resto.","Portare la miscela a 85 °C (pastorizzazione alta) e mantenere per 15 secondi.","Raffreddare rapidamente a +4 °C in abbattitore o in bagno di acqua e ghiaccio.","Maturare in frigorifero a 2–4 °C per almeno 4 ore (ideale: 12 ore).","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere a −18 °C per almeno 2 ore prima del servizio."],"notaTecnica":"Il fior di panna non contiene tuorli: la struttura dipende interamente dalle proteine del latte e dallo stabilizzante. La maturazione prolungata migliora l'idratazione dello stabilizzante e la cremosità finale."},{"id":"cioccolato","nome":"Cioccolato","categoria":"crema","payoff":"Cacao amaro bilanciato. Scuro ma non pesante.","ingredienti":[{"id":"latte-intero","g_per_kg":580},{"id":"panna-35","g_per_kg":80},{"id":"saccarosio","g_per_kg":155},{"id":"latte-polvere-scremato","g_per_kg":40},{"id":"destrosio-monoidrato","g_per_kg":30},{"id":"cacao-amaro-22","g_per_kg":100},{"id":"stabilizzante","g_per_kg":8}],"ingredientiModificabili":[{"nome":"Cacao amaro 22%","min":60,"max":140},{"nome":"Panna 35%","min":40,"max":130},{"nome":"Saccarosio","min":110,"max":200}],"procedimento":["Pesare tutti gli ingredienti.","Setacciare il cacao amaro e mescolarlo a secco con saccarosio e destrosio.","Sciogliere il latte in polvere nel latte intero, poi aggiungere la miscela di zuccheri e cacao.","Unire la panna e lo stabilizzante (disperso in una piccola parte di saccarosio) fin dall'inizio del riscaldamento.","Portare a 85 °C e mantenere per 15 secondi (pastorizzazione alta).","Raffreddare rapidamente a +4 °C.","Maturare a 2–4 °C per almeno 6 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere e conservare a −18 °C."],"notaTecnica":"Il cacao amaro al 22% di grassi introduce grassi vegetali che si solidificano molto a temperatura negativa, riducendo il PAC effettivo. Il destrosio nella ricetta compensa parzialmente questo effetto secondo il metodo Corvitto (PAC corretto = Zuccheri% − 1,4 × Grassi_vegetali%)."},{"id":"pistacchio","nome":"Pistacchio","categoria":"crema","payoff":"Pasta di pistacchio pura. Nessun colorante.","ingredienti":[{"id":"latte-intero","g_per_kg":540},{"id":"panna-35","g_per_kg":80},{"id":"saccarosio","g_per_kg":160},{"id":"latte-polvere-scremato","g_per_kg":40},{"id":"pasta-pistacchio-pura","g_per_kg":120},{"id":"glucosio-42de","g_per_kg":50},{"id":"stabilizzante","g_per_kg":5}],"ingredientiModificabili":[{"nome":"Pasta di pistacchio pura","min":80,"max":180},{"nome":"Panna 35%","min":40,"max":130},{"nome":"Saccarosio","min":120,"max":210}],"procedimento":["Pesare tutti gli ingredienti.","Sciogliere il latte in polvere nel latte intero a temperatura ambiente.","Aggiungere saccarosio, sciroppo di glucosio e stabilizzante (disperso in parte dello zucchero).","Portare a 85 °C e mantenere per 15 secondi (pastorizzazione alta).","Raffreddare a +4 °C, poi incorporare la pasta di pistacchio pura mescolando con frusta fino a emulsione completa.","Maturare a 2–4 °C per almeno 6 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere e conservare a −18 °C."],"notaTecnica":"La pasta di pistacchio pura apporta circa il 55% di grassi vegetali: il tenore totale di grassi della miscela sale sensibilmente. La panna è ridotta rispetto a una base crema standard per mantenere l'equilibrio. La pasta si aggiunge a freddo per preservare i profumi volatili del pistacchio. Nota sul bilanciamento: i grassi vegetali del pistacchio abbassano il PAC effettivo sotto il range standard e alzano i solidi totali oltre il 44%. Questi due parametri in attenzione sono un compromesso noto e documentato per la categoria frutta secca — non un errore di bilanciamento.","eccezioniSoglie":["solidi"]},{"id":"nocciola","nome":"Nocciola","categoria":"crema","payoff":"Pasta di nocciola pura. Amaro tostato, nessun aggiustamento.","ingredienti":[{"id":"latte-intero","g_per_kg":540},{"id":"panna-35","g_per_kg":80},{"id":"saccarosio","g_per_kg":160},{"id":"latte-polvere-scremato","g_per_kg":40},{"id":"pasta-nocciola-pura","g_per_kg":110},{"id":"glucosio-42de","g_per_kg":50},{"id":"stabilizzante","g_per_kg":5}],"ingredientiModificabili":[{"nome":"Pasta di nocciola pura","min":70,"max":160},{"nome":"Panna 35%","min":40,"max":130},{"nome":"Saccarosio","min":120,"max":210}],"procedimento":["Pesare tutti gli ingredienti.","Sciogliere il latte in polvere nel latte intero a temperatura ambiente.","Aggiungere saccarosio, sciroppo di glucosio e stabilizzante (disperso in parte dello zucchero).","Portare a 85 °C e mantenere per 15 secondi (pastorizzazione alta).","Raffreddare a +4 °C, poi incorporare la pasta di nocciola pura mescolando con frusta fino a emulsione completa.","Maturare a 2–4 °C per almeno 6 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere e conservare a −18 °C."],"notaTecnica":"La pasta di nocciola pura apporta circa il 60% di grassi vegetali — leggermente più della pasta di pistacchio (55%). Come per tutti i gusti a frutta secca, i grassi vegetali si solidificano a temperature negative molto più del grasso del latte e non hanno potere anticongelante: questo abbassa il PAC effettivo sotto il range standard e alza i solidi totali oltre il 44%. Sono due parametri in attenzione strutturali — un compromesso noto e documentato (metodo Corvitto) per l'intera categoria frutta secca, non un errore di bilanciamento. La pasta si aggiunge a freddo dopo la pastorizzazione per preservare i profumi volatili della nocciola tostata.","eccezioniSoglie":["solidi"]},{"id":"fragola","nome":"Fragola","categoria":"frutta","payoff":"Polpa fresca. Frutta vera, non aromi.","ingredienti":[{"id":"fragole-fresche","g_per_kg":300},{"id":"latte-intero","g_per_kg":480},{"id":"saccarosio","g_per_kg":110},{"id":"destrosio-monoidrato","g_per_kg":75},{"id":"glucosio-42de","g_per_kg":30},{"id":"stabilizzante","g_per_kg":5}],"ingredientiModificabili":[{"nome":"Fragole fresche","min":200,"max":400},{"nome":"Latte intero","min":380,"max":580},{"nome":"Saccarosio","min":80,"max":150}],"procedimento":["Pesare tutti gli ingredienti; usare fragole fresche mature o surgelate di qualità.","Frullare le fragole e passarle al setaccio fine per rimuovere i semi.","Sciogliere saccarosio, destrosio e sciroppo di glucosio nel latte freddo mescolando con frusta.","Aggiungere la polpa di fragola e lo stabilizzante a freddo; mescolare fino a completa idratazione (15–20 min).","Non pastorizzare se si usa latte UHT: il processo a freddo preserva i profumi volatili della frutta. Se si usa latte fresco pastorizzato, seguire le indicazioni del produttore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere e conservare a −18 °C."],"notaTecnica":"Gelato alla frutta con base latte: struttura a metà tra crema e sorbetto. La quota di latte apporta SLNG e grassi sufficienti a dare cremosità senza coprire il profilo aromatico della fragola. Destrosio e glucosio abbassano il PAC senza alzare eccessivamente il POD, compensando la bassa zuccherosità naturale della fragola (≈9%). Bilanciamento verificato sui thresholds PAC/POD della famiglia creme (non esistono range pubblicati specifici per 'gelato alla frutta con latte' nelle fonti professionali consultate)."},{"id":"banana","nome":"Banana","categoria":"frutta","payoff":"Banana matura, base latte. Cremoso e naturalmente dolce.","ingredienti":[{"id":"banana-fresca","g_per_kg":250},{"id":"latte-intero","g_per_kg":500},{"id":"saccarosio","g_per_kg":90},{"id":"destrosio-monoidrato","g_per_kg":60},{"id":"glucosio-42de","g_per_kg":20},{"id":"stabilizzante","g_per_kg":5}],"ingredientiModificabili":[{"nome":"Banana fresca","min":150,"max":350},{"nome":"Latte intero","min":400,"max":600},{"nome":"Saccarosio","min":60,"max":130}],"procedimento":["Pesare tutti gli ingredienti; usare banane mature (buccia con qualche macchia nera) per massima dolcezza e aroma.","Sbucciare e frullare le banane con un cucchiaio di succo di limone per prevenire l'ossidazione della polpa.","Sciogliere saccarosio, destrosio e sciroppo di glucosio nel latte freddo mescolando con frusta.","Aggiungere la polpa di banana e lo stabilizzante a freddo; mescolare fino a completa idratazione (15–20 min).","Non pastorizzare se si usa latte UHT: il processo a freddo preserva i profumi volatili della frutta.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere e conservare a −18 °C."],"notaTecnica":"La banana matura ha un contenuto di zuccheri naturali elevato (circa 19%), che riduce la quantità di saccarosio aggiunto rispetto ad altri gelati alla frutta. Il succo di limone aggiunto durante la frullatura è tecnico, non gustativo: rallenta l'ossidazione enzimatica (imbrunimento della polpa) senza alterare il profilo aromatico al dosaggio usato."},{"id":"limone","nome":"Sorbetto Limone","categoria":"sorbetto","payoff":"Succo di limone siciliano. Pulito, acidulo, zero grassi.","ingredienti":[{"id":"succo-di-limone","g_per_kg":365},{"id":"acqua","g_per_kg":290},{"id":"saccarosio","g_per_kg":140},{"id":"glucosio-42de","g_per_kg":50},{"id":"destrosio-monoidrato","g_per_kg":60},{"id":"stabilizzante","g_per_kg":5}],"ingredientiModificabili":[{"nome":"Succo di limone","min":280,"max":440},{"nome":"Saccarosio","min":100,"max":180},{"nome":"Sciroppo di glucosio 42DE","min":25,"max":90}],"procedimento":["Spremitura e filtratura del succo di limone; pesare le dosi.","Portare acqua e saccarosio a 80 °C mescolando per formare uno sciroppo; aggiungere lo sciroppo di glucosio, mescolare fino a dissoluzione.","Raffreddare lo sciroppo a temperatura ambiente, poi a +4 °C.","Unire il succo di limone freddo allo sciroppo; aggiungere lo stabilizzante per freddo mescolando bene.","Maturare in frigorifero per 2–4 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere a −18 °C per almeno 2 ore."],"notaTecnica":"L'acidità del limone abbassa il pH della miscela, inibendo la crescita batterica — il succo di frutta non necessita di pastorizzazione. Lo sciroppo di base viene portato a 80 °C per la completa dissoluzione degli zuccheri. SCELTA DOCUMENTATA: lo sciroppo di glucosio 42DE costituisce qui circa il 55% del totale zuccheri aggiunti, oltre la regola pratica generica (zuccheri secondi max 20-25%, gelato-reference.md §3) — necessario per portare POD e PAC dentro i range stretti del sorbetto agrumi (POD 20-23.5, PAC 27.5-37.5) mantenendo zuccheri al 28-30%. Coerente con l'indicazione dello stesso documento: va sempre verificato il risultato finale di POD/PAC, non solo la proporzione di sostituzione."},{"id":"lampone","nome":"Sorbetto Lampone","categoria":"sorbetto","payoff":"Polpa di lampone al setaccio. Acido, netto, senza latticini.","ingredienti":[{"id":"lamponi-polpa","g_per_kg":425},{"id":"acqua","g_per_kg":260},{"id":"saccarosio","g_per_kg":140},{"id":"glucosio-42de","g_per_kg":60},{"id":"destrosio-monoidrato","g_per_kg":15},{"id":"stabilizzante","g_per_kg":5}],"ingredientiModificabili":[{"nome":"Lamponi (polpa)","min":330,"max":520},{"nome":"Saccarosio","min":100,"max":180},{"nome":"Destrosio (monoidrato)","min":5,"max":35}],"procedimento":["Frullare i lamponi freschi o surgelati e passarli al setaccio fine per eliminare i semi.","Portare acqua e saccarosio a 80 °C mescolando per formare uno sciroppo; aggiungere lo sciroppo di glucosio e il destrosio, mescolare fino a dissoluzione.","Raffreddare lo sciroppo a temperatura ambiente, poi a +4 °C.","Unire la polpa di lampone fredda allo sciroppo; aggiungere lo stabilizzante per freddo mescolando bene.","Maturare in frigorifero per 2–4 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere a −18 °C per almeno 2 ore."],"notaTecnica":"Il sorbetto di lamponi non necessita di pastorizzazione grazie all'acidità naturale della frutta. I semi vengono rimossi con setaccio fine prima della lavorazione. Lo sciroppo di glucosio e il destrosio insieme migliorano la spatolabilità e frenano la ricristallizzazione tipica delle puree di frutti rossi, mantenendo zuccheri/POD/PAC nel range ottimale del sorbetto."},{"id":"cocco-vegano","nome":"Cocco Vegano","categoria":"vegano","payoff":"Latte di cocco intero, nessun latticino.","ingredienti":[{"id":"latte-di-cocco-intero","g_per_kg":400},{"id":"acqua","g_per_kg":320},{"id":"inulina","g_per_kg":30},{"id":"stabilizzante","g_per_kg":5},{"id":"saccarosio","g_per_kg":60},{"id":"destrosio-monoidrato","g_per_kg":85},{"id":"glucosio-42de","g_per_kg":30}],"ingredientiModificabili":[{"nome":"Latte di cocco intero","min":300,"max":550},{"nome":"Saccarosio","min":50,"max":140},{"nome":"Destrosio (monoidrato)","min":30,"max":90}],"procedimento":["Pesare tutti gli ingredienti; usare latte di cocco intero (non light).","Mescolare a freddo saccarosio, destrosio, sciroppo di glucosio e inulina nel latte di cocco e nell'acqua.","Disperdere lo stabilizzante in una piccola quantità di zucchero e unire alla miscela.","Portare a 80 °C mescolando continuamente; mantenere per 20 secondi.","Raffreddare rapidamente a +4 °C.","Maturare in frigorifero a 2–4 °C per almeno 4 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere e conservare a −18 °C."],"notaTecnica":"In assenza di proteine del latte, la struttura si affida a grassi vegetali e fibre. L'inulina sostituisce parzialmente gli SLNG: lega l'acqua libera, migliora il corpo e limita i cristalli di ghiaccio. Dose massima consigliata: 2-3% della miscela per evitare effetti lassativi. ECCEZIONE DOCUMENTATA: \\"Altri solidi\\" risulta strutturalmente sotto il range target (32-40% solidi totali raggiunto, ma altri solidi ~4.4% contro un target 7-17%) — con gli ingredienti vegani disponibili (latte di cocco, povero di fibre/proteine; inulina capata alla dose di sicurezza), non è raggiungibile senza superare la dose massima consigliata di inulina. Stesso tipo di compromesso già accettato per i gusti a frutta secca sui solidi totali — non è un errore di bilanciamento, è un limite reale della categoria con questa base.","eccezioniSoglie":["altri"]},{"id":"noci-vegano","nome":"Noci Vegano","categoria":"vegano","payoff":"Pasta di noci e latte di avena. Senza latticini.","ingredienti":[{"id":"latte-di-avena","g_per_kg":600},{"id":"pasta-di-noci","g_per_kg":80},{"id":"inulina","g_per_kg":40},{"id":"stabilizzante","g_per_kg":5},{"id":"saccarosio","g_per_kg":60},{"id":"destrosio-monoidrato","g_per_kg":55},{"id":"glucosio-42de","g_per_kg":20}],"ingredientiModificabili":[{"nome":"Pasta di noci","min":50,"max":130},{"nome":"Saccarosio","min":40,"max":160},{"nome":"Inulina","min":20,"max":60}],"procedimento":["Pesare tutti gli ingredienti; usare pasta di noci 100% priva di oli aggiunti.","Mescolare a freddo saccarosio, destrosio, sciroppo di glucosio e inulina nel latte di avena.","Disperdere lo stabilizzante in una piccola quantità di zucchero e unire alla miscela.","Portare a 80 °C mescolando continuamente; mantenere per 20 secondi.","Raffreddare rapidamente a +4 °C; incorporare la pasta di noci a freddo mescolando con frusta fino a emulsione uniforme.","Maturare a 2–4 °C per almeno 4 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere e conservare a −18 °C."],"notaTecnica":"In assenza di proteine del latte, la struttura si affida a grassi vegetali delle noci e fibre dell'inulina. Le noci apportano circa il 65% di grassi vegetali — tra i più alti delle paste di frutta secca — ricchi di acidi grassi polinsaturi omega-3. La pasta viene aggiunta a freddo dopo la pastorizzazione della base per preservare i profumi delicati. Il PAC è leggermente sotto il range standard: strutturale per i grassi vegetali delle noci, stesso compromesso documentato di nocciola e pistacchio."},{"id":"mandorla-vegana","nome":"Mandorla Vegana","categoria":"vegano","payoff":"Pasta di mandorla pura e latte di riso. Senza latticini.","ingredienti":[{"id":"latte-di-riso","g_per_kg":600},{"id":"pasta-mandorla-pura","g_per_kg":90},{"id":"inulina","g_per_kg":40},{"id":"stabilizzante","g_per_kg":5},{"id":"saccarosio","g_per_kg":50},{"id":"destrosio-monoidrato","g_per_kg":40},{"id":"glucosio-42de","g_per_kg":25}],"ingredientiModificabili":[{"nome":"Pasta di mandorla pura","min":60,"max":140},{"nome":"Saccarosio","min":35,"max":140},{"nome":"Sciroppo di glucosio 42DE","min":20,"max":60}],"procedimento":["Pesare tutti gli ingredienti; usare pasta di mandorla pura (100% mandorle, senza zuccheri aggiunti).","Mescolare a freddo saccarosio, destrosio, sciroppo di glucosio e inulina nel latte di riso.","Disperdere lo stabilizzante in una piccola quantità di zucchero e unire alla miscela.","Portare a 80 °C mescolando continuamente; mantenere per 20 secondi.","Raffreddare rapidamente a +4 °C; incorporare la pasta di mandorla a freddo mescolando con frusta fino a emulsione uniforme.","Maturare a 2–4 °C per almeno 4 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere e conservare a −18 °C."],"notaTecnica":"Il latte di riso, più ricco di carboidrati naturali rispetto al latte di avena, riduce la quantità di saccarosio aggiunto e bilancia naturalmente la dolcezza della pasta di mandorla. L'inulina svolge il ruolo di agente strutturante in sostituzione degli SLNG. La mandorla è la frutta secca con il profilo grasso più delicato tra quelle usate nelle ricette vegane di questa serie: tutti i parametri di bilanciamento rientrano nei range standard."},{"id":"caffe","nome":"Caffè","categoria":"crema","payoff":"Espresso vero, non aroma. Intenso ma non amaro.","ingredienti":[{"id":"latte-intero","g_per_kg":540},{"id":"panna-35","g_per_kg":90},{"id":"saccarosio","g_per_kg":160},{"id":"latte-polvere-scremato","g_per_kg":45},{"id":"glucosio-42de","g_per_kg":40},{"id":"caffe-espresso","g_per_kg":120},{"id":"stabilizzante","g_per_kg":8}],"ingredientiModificabili":[{"nome":"Caffè espresso (forte)","min":80,"max":180},{"nome":"Saccarosio","min":120,"max":200},{"nome":"Panna 35%","min":50,"max":140}],"procedimento":["Pesare tutti gli ingredienti; preparare un espresso forte (o caffè moka molto concentrato) e lasciarlo raffreddare completamente.","Sciogliere il latte in polvere scremato nel latte intero a temperatura ambiente.","Aggiungere panna, saccarosio e sciroppo di glucosio; disperdere lo stabilizzante in una piccola quantità di saccarosio e unire al resto.","Portare la miscela a 85 °C e mantenere per 15 secondi (pastorizzazione alta).","Raffreddare rapidamente a +4 °C, poi incorporare il caffè freddo mescolando bene.","Maturare in frigorifero per almeno 4 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere e conservare a −18 °C."],"notaTecnica":"Il caffè si aggiunge a freddo, dopo la pastorizzazione della base, per preservare gli aromi volatili che il calore prolungato disperderebbe. Il suo contributo al bilanciamento è quasi interamente sugli \\"altri solidi\\" (i solidi disciolti dell'estrazione, circa 9-11% in un espresso standard) — zuccheri, potere dolcificante e anticongelante derivano quasi interamente dagli altri ingredienti della base crema."},{"id":"stracciatella","nome":"Stracciatella","categoria":"crema","payoff":"Fior di panna con scaglie di cioccolato fondente, alla vecchia maniera.","ingredienti":[{"id":"latte-intero","g_per_kg":600},{"id":"panna-35","g_per_kg":130},{"id":"saccarosio","g_per_kg":160},{"id":"latte-polvere-scremato","g_per_kg":50},{"id":"glucosio-42de","g_per_kg":30},{"id":"cioccolato-fondente-copertura","g_per_kg":60},{"id":"stabilizzante","g_per_kg":8}],"ingredientiModificabili":[{"nome":"Cioccolato fondente di copertura (70%)","min":40,"max":90},{"nome":"Panna 35%","min":90,"max":170},{"nome":"Saccarosio","min":120,"max":200}],"procedimento":["Pesare tutti gli ingredienti.","Sciogliere il latte in polvere scremato nel latte intero a temperatura ambiente.","Aggiungere panna, saccarosio e sciroppo di glucosio; disperdere lo stabilizzante in una piccola quantità di saccarosio e unire al resto.","Portare a 85 °C e mantenere per 15 secondi (pastorizzazione alta).","Raffreddare rapidamente a +4 °C.","Maturare in frigorifero per almeno 4 ore.","Sciogliere il cioccolato fondente a bagnomaria (massimo 45 °C) e tenerlo fluido.","Mantecare la base fino quasi a fine corsa; negli ultimi 1-2 minuti versare il cioccolato fuso a filo sottile e continuo nella macchina in movimento: il contatto con la massa già fredda lo solidifica istantaneamente in scaglie sottili.","Abbattere e conservare a −18 °C."],"notaTecnica":"La tecnica classica della stracciatella prevede di versare il cioccolato fuso a filo durante gli ultimi istanti della mantecazione, non di miscelarlo nella base liquida: il contrasto termico con la massa già gelata lo solidifica in scaglie sottili e irregolari, distinte dalla crema. Per il bilanciamento il cioccolato è comunque conteggiato come parte della miscela totale (60g su circa 1038g), anche se non è mai sciolto nella fase liquida della base."},{"id":"zabaione","nome":"Zabaione","categoria":"crema","payoff":"Tuorli, marsala, zucchero. La ricetta dei nonni, vera.","ingredienti":[{"id":"latte-intero","g_per_kg":500},{"id":"panna-35","g_per_kg":100},{"id":"saccarosio","g_per_kg":170},{"id":"latte-polvere-scremato","g_per_kg":40},{"id":"tuorlo-uovo","g_per_kg":80},{"id":"marsala","g_per_kg":60},{"id":"glucosio-42de","g_per_kg":30},{"id":"stabilizzante","g_per_kg":8}],"ingredientiModificabili":[{"nome":"Tuorlo d'uovo (pastorizzato)","min":50,"max":110},{"nome":"Marsala (vino liquoroso dolce)","min":30,"max":90},{"nome":"Saccarosio","min":130,"max":210}],"procedimento":["Pesare tutti gli ingredienti. Usare tuorli pastorizzati (in brick) oppure pastorizzare personalmente le uova fresche: è un passaggio di sicurezza alimentare obbligatorio, non opzionale, per eliminare il rischio Salmonella.","Sciogliere il latte in polvere scremato nel latte intero a temperatura ambiente.","Sbattere i tuorli con una parte del saccarosio fino a renderli chiari e spumosi.","Unire il composto di tuorli al latte/panna insieme al resto del saccarosio e allo sciroppo di glucosio; disperdere lo stabilizzante in una piccola quantità di zucchero e unire.","Portare la miscela a 85 °C e mantenere per almeno 15 secondi — con i tuorli è particolarmente importante non superare gli 85 °C, per evitare la coagulazione (effetto \\"frittata\\").","Raffreddare rapidamente a +4 °C; incorporare il marsala a freddo, mescolando bene.","Maturare in frigorifero per almeno 4 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere e conservare a −18 °C."],"notaTecnica":"Prima ricetta del catalogo con le uova: la pastorizzazione a 85 °C è qui doppiamente necessaria — non solo per la sicurezza alimentare (i tuorli crudi possono veicolare Salmonella), ma anche per la struttura, poiché i tuorli coagulano e danno corpo alla crema, come in un vero zabaione da pasticceria. Il marsala si aggiunge sempre a freddo, dopo la pastorizzazione: il calore ne disperderebbe sia l'alcol che l'aroma. Nota di modello: l'alcol (18% vol nel marsala) abbassa il punto di congelamento della miscela in un modo che il calcolo POD/PAC qui non capta esplicitamente — alle dosi indicate l'effetto è contenuto, ma non aumentare il Marsala oltre il range massimo indicato senza verificare la consistenza in mantecazione."},{"id":"pesca","nome":"Pesca","categoria":"frutta","payoff":"Pesche mature, base latte. Estate vera.","ingredienti":[{"id":"pesca-fresca","g_per_kg":320},{"id":"latte-intero","g_per_kg":480},{"id":"saccarosio","g_per_kg":95},{"id":"destrosio-monoidrato","g_per_kg":65},{"id":"glucosio-42de","g_per_kg":25},{"id":"stabilizzante","g_per_kg":5}],"ingredientiModificabili":[{"nome":"Pesca fresca","min":220,"max":420},{"nome":"Latte intero","min":380,"max":580},{"nome":"Saccarosio","min":65,"max":130}],"procedimento":["Pesare tutti gli ingredienti; usare pesche mature, sbucciate e denocciolate.","Frullare le pesche e passarle al setaccio se la buccia non è stata rimossa completamente.","Sciogliere saccarosio, destrosio e sciroppo di glucosio nel latte freddo mescolando con frusta.","Aggiungere la polpa di pesca e lo stabilizzante a freddo; mescolare fino a completa idratazione (15-20 min).","Non pastorizzare se si usa latte UHT: il processo a freddo preserva i profumi volatili della frutta.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere e conservare a −18 °C."],"notaTecnica":"Gelato alla frutta con base latte, stessa famiglia di Fragola e Banana. La pesca ha un contenuto zuccherino naturale medio (14%): destrosio e glucosio coprono la quota di PAC necessaria senza eccedere sul POD. Bilanciamento verificato sui thresholds della famiglia creme, come da nota in gelato-reference.md sull'assenza di range pubblicati specifici per la sottocategoria."},{"id":"mango","nome":"Mango","categoria":"frutta","payoff":"Mango maturo, base latte. Tropicale, non stucchevole.","ingredienti":[{"id":"mango-fresco","g_per_kg":300},{"id":"latte-intero","g_per_kg":480},{"id":"saccarosio","g_per_kg":100},{"id":"destrosio-monoidrato","g_per_kg":55},{"id":"glucosio-42de","g_per_kg":35},{"id":"stabilizzante","g_per_kg":5}],"ingredientiModificabili":[{"nome":"Mango fresco","min":200,"max":400},{"nome":"Latte intero","min":380,"max":580},{"nome":"Saccarosio","min":70,"max":140}],"procedimento":["Pesare tutti gli ingredienti; usare mango maturo (polpa morbida, profumo intenso), sbucciato e privato del nocciolo.","Frullare la polpa di mango fino a purea omogenea.","Sciogliere saccarosio, destrosio e sciroppo di glucosio nel latte freddo mescolando con frusta.","Aggiungere la purea di mango e lo stabilizzante a freddo; mescolare fino a completa idratazione (15-20 min).","Non pastorizzare se si usa latte UHT: il processo a freddo preserva i profumi volatili della frutta.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere e conservare a −18 °C."],"notaTecnica":"Il mango ha un profilo aromatico molto volatile: il processo a freddo (nessuna pastorizzazione con latte UHT) è particolarmente importante qui per non disperdere il profumo caratteristico. Stessa famiglia bilanciamento di Fragola/Banana/Pesca."},{"id":"ananas","nome":"Ananas","categoria":"frutta","payoff":"Ananas fresco, base latte. Acidulo e succoso.","ingredienti":[{"id":"ananas-fresco","g_per_kg":330},{"id":"latte-intero","g_per_kg":470},{"id":"saccarosio","g_per_kg":105},{"id":"destrosio-monoidrato","g_per_kg":50},{"id":"glucosio-42de","g_per_kg":35},{"id":"stabilizzante","g_per_kg":5}],"ingredientiModificabili":[{"nome":"Ananas fresco","min":230,"max":430},{"nome":"Latte intero","min":370,"max":570},{"nome":"Saccarosio","min":75,"max":145}],"procedimento":["Pesare tutti gli ingredienti; usare ananas fresco maturo, privato della corteccia e della parte centrale legnosa.","Frullare la polpa fino a purea omogenea.","IMPORTANTE: scaldare brevemente la purea di ananas crudo a 70-80 °C per 2-3 minuti (o usare ananas già cotto/in scatola) prima di unirla al latte — la bromelina, un enzima naturale dell'ananas fresco, scompone le proteine del latte e può causare amarore o cagliatura se la purea cruda viene mescolata direttamente a freddo nella base.","Lasciare raffreddare completamente la purea trattata.","Sciogliere saccarosio, destrosio e sciroppo di glucosio nel latte freddo mescolando con frusta.","Aggiungere la purea di ananas (ormai inattivata) e lo stabilizzante; mescolare fino a completa idratazione (15-20 min).","Maturare in frigorifero per almeno 4 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere e conservare a −18 °C."],"notaTecnica":"Unico gusto frutta del catalogo che richiede un trattamento termico della polpa prima dell'unione alla base latte: la bromelina dell'ananas crudo è un enzima proteolitico che degrada le proteine del latte (caseina), causando potenziale amarore o consistenza cagliata se non inattivata con un breve riscaldamento. Per il resto, stesso schema di bilanciamento della famiglia frutta-con-latte."},{"id":"frutti-di-bosco","nome":"Frutti di Bosco","categoria":"frutta","payoff":"Mirtilli, more, lamponi e ribes. Frutti rossi, non addolciti troppo.","ingredienti":[{"id":"frutti-di-bosco-misti","g_per_kg":350},{"id":"latte-intero","g_per_kg":470},{"id":"saccarosio","g_per_kg":125},{"id":"destrosio-monoidrato","g_per_kg":55},{"id":"glucosio-42de","g_per_kg":40},{"id":"stabilizzante","g_per_kg":5}],"ingredientiModificabili":[{"nome":"Frutti di bosco misti (polpa)","min":250,"max":450},{"nome":"Latte intero","min":370,"max":570},{"nome":"Saccarosio","min":90,"max":170}],"procedimento":["Pesare tutti gli ingredienti; usare un mix di mirtilli, more, lamponi e ribes freschi o surgelati.","Frullare i frutti e passarli al setaccio fine per eliminare i semi (soprattutto lamponi e more).","Sciogliere saccarosio, destrosio e sciroppo di glucosio nel latte freddo mescolando con frusta.","Aggiungere la polpa di frutti di bosco e lo stabilizzante a freddo; mescolare fino a completa idratazione (15-20 min).","Non pastorizzare se si usa latte UHT: il processo a freddo preserva i profumi volatili della frutta.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere e conservare a −18 °C."],"notaTecnica":"Il mix di frutti di bosco ha un contenuto zuccherino naturale più basso (8% medio, contro 9-19% degli altri frutti del catalogo) e un'acidità più marcata, tipica dei frutti rossi: la quota di saccarosio aggiunto è proporzionalmente più alta per compensare. Stessa famiglia di bilanciamento (frutta con base latte) di Fragola/Banana/Pesca/Mango."},{"id":"arancia","nome":"Sorbetto Arancia","categoria":"sorbetto","payoff":"Succo d'arancia spremuto. Pulito, dolce, mai stucchevole.","ingredienti":[{"id":"succo-arancia","g_per_kg":365},{"id":"acqua","g_per_kg":305},{"id":"saccarosio","g_per_kg":90},{"id":"glucosio-42de","g_per_kg":90},{"id":"destrosio-monoidrato","g_per_kg":45},{"id":"stabilizzante","g_per_kg":5}],"ingredientiModificabili":[{"nome":"Succo d'arancia","min":280,"max":440},{"nome":"Saccarosio","min":65,"max":130},{"nome":"Sciroppo di glucosio 42DE","min":60,"max":130}],"procedimento":["Spremitura e filtratura del succo d'arancia; pesare le dosi.","Portare acqua e saccarosio a 80 °C mescolando per formare uno sciroppo; aggiungere lo sciroppo di glucosio, mescolare fino a dissoluzione.","Raffreddare lo sciroppo a temperatura ambiente, poi a +4 °C.","Unire il succo d'arancia freddo allo sciroppo; aggiungere lo stabilizzante per freddo mescolando bene.","Maturare in frigorifero per 2-4 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere a −18 °C per almeno 2 ore."],"notaTecnica":"L'acidità dell'arancia, pur meno marcata di quella del limone, è comunque sufficiente a non richiedere pastorizzazione. Il succo d'arancia ha un contenuto zuccherino naturale variabile per stagione e varietà (10% medio) — verificare e correggere il saccarosio se il frutto risulta più o meno dolce del previsto. Stesso schema di bilanciamento del Sorbetto Limone."},{"id":"melone","nome":"Sorbetto Melone","categoria":"sorbetto","payoff":"Melone maturo, polpa pura. Fresco, leggero, estivo.","ingredienti":[{"id":"melone-polpa","g_per_kg":300},{"id":"acqua","g_per_kg":375},{"id":"saccarosio","g_per_kg":140},{"id":"glucosio-42de","g_per_kg":60},{"id":"destrosio-monoidrato","g_per_kg":30},{"id":"stabilizzante","g_per_kg":5}],"ingredientiModificabili":[{"nome":"Melone (polpa)","min":230,"max":400},{"nome":"Saccarosio","min":100,"max":180},{"nome":"Sciroppo di glucosio 42DE","min":40,"max":90}],"procedimento":["Frullare la polpa di melone maturo (privata della scorza e dei semi) fino a purea omogenea.","Portare acqua e saccarosio a 80 °C mescolando per formare uno sciroppo; aggiungere lo sciroppo di glucosio, mescolare fino a dissoluzione.","Raffreddare lo sciroppo a temperatura ambiente, poi a +4 °C.","Unire la purea di melone fredda allo sciroppo; aggiungere lo stabilizzante per freddo mescolando bene.","Maturare in frigorifero per 2-4 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere a −18 °C per almeno 2 ore."],"notaTecnica":"Il melone ha bassa acidità (a differenza degli agrumi): la pastorizzazione non è comunque necessaria grazie all'alto contenuto d'acqua e basso pH residuo della polpa fresca, ma la maturazione in frigorifero resta importante per l'idratazione dello stabilizzante. Stesso schema di bilanciamento di Limone/Arancia. Nota dati: il valore zuccheri del melone è stato corretto da una sovrastima iniziale (11%->7%, fonte Torrinomedica/USDA) — la ricetta è stata riequilibrata di conseguenza."},{"id":"pera","nome":"Sorbetto Pera","categoria":"sorbetto","payoff":"Pera matura, polpa pura. Delicato, mai acidulo.","ingredienti":[{"id":"pera-polpa","g_per_kg":300},{"id":"acqua","g_per_kg":380},{"id":"saccarosio","g_per_kg":100},{"id":"glucosio-42de","g_per_kg":40},{"id":"destrosio-monoidrato","g_per_kg":75},{"id":"stabilizzante","g_per_kg":5}],"ingredientiModificabili":[{"nome":"Pera (polpa)","min":230,"max":400},{"nome":"Saccarosio","min":70,"max":140},{"nome":"Sciroppo di glucosio 42DE","min":25,"max":65}],"procedimento":["Sbucciare e frullare le pere mature con un cucchiaio di succo di limone per prevenire l'ossidazione della polpa (il classico imbrunimento).","Portare acqua e saccarosio a 80 °C mescolando per formare uno sciroppo; aggiungere lo sciroppo di glucosio, mescolare fino a dissoluzione.","Raffreddare lo sciroppo a temperatura ambiente, poi a +4 °C.","Unire la purea di pera fredda allo sciroppo; aggiungere lo stabilizzante per freddo mescolando bene.","Maturare in frigorifero per 2-4 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere a −18 °C per almeno 2 ore."],"notaTecnica":"La pera ossida molto rapidamente una volta tagliata o frullata (imbrunimento enzimatico): il succo di limone aggiunto durante la frullatura è tecnico, non gustativo, e non altera il bilanciamento al dosaggio usato (non incluso come ingrediente separato nella miscela). Stesso schema di bilanciamento di Limone/Arancia/Melone."},{"id":"kiwi","nome":"Sorbetto Kiwi","categoria":"sorbetto","payoff":"Kiwi maturo, polpa pura. Verde, acidulo, vivace.","ingredienti":[{"id":"kiwi-polpa","g_per_kg":375},{"id":"acqua","g_per_kg":305},{"id":"saccarosio","g_per_kg":120},{"id":"glucosio-42de","g_per_kg":70},{"id":"destrosio-monoidrato","g_per_kg":30},{"id":"stabilizzante","g_per_kg":5}],"ingredientiModificabili":[{"nome":"Kiwi (polpa)","min":280,"max":450},{"nome":"Saccarosio","min":85,"max":160},{"nome":"Sciroppo di glucosio 42DE","min":50,"max":100}],"procedimento":["Sbucciare e frullare i kiwi maturi; passare al setaccio fine se si vogliono eliminare i semini neri (opzionale, non incide sul bilanciamento).","Portare acqua e saccarosio a 80 °C mescolando per formare uno sciroppo; aggiungere lo sciroppo di glucosio, mescolare fino a dissoluzione.","Raffreddare lo sciroppo a temperatura ambiente, poi a +4 °C.","Unire la purea di kiwi fredda allo sciroppo; aggiungere lo stabilizzante per freddo mescolando bene.","Maturare in frigorifero per 2-4 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere a −18 °C per almeno 2 ore."],"notaTecnica":"Il kiwi contiene actinidina, un enzima proteolitico simile alla bromelina dell'ananas — ma trattandosi di un sorbetto puro senza latte, non c'è rischio di cagliatura proteica come nell'Ananas; l'unico effetto possibile è una purea che si fa leggermente più liquida se lasciata cruda a lungo prima della mantecazione, non un problema di bilanciamento. Stesso schema di Limone/Arancia/Melone/Pera."},{"id":"mandarino","nome":"Sorbetto Mandarino","categoria":"sorbetto","payoff":"Mandarino, succo e polpa. Più dolce e meno acidulo del limone.","ingredienti":[{"id":"mandarino-fresco","g_per_kg":435},{"id":"acqua","g_per_kg":265},{"id":"saccarosio","g_per_kg":120},{"id":"glucosio-42de","g_per_kg":50},{"id":"destrosio-monoidrato","g_per_kg":30},{"id":"stabilizzante","g_per_kg":5}],"ingredientiModificabili":[{"nome":"Mandarino (succo e polpa)","min":320,"max":500},{"nome":"Saccarosio","min":85,"max":160},{"nome":"Sciroppo di glucosio 42DE","min":35,"max":75}],"procedimento":["Spremitura del succo di mandarino, eventualmente con una piccola quota di polpa passata al setaccio per il corpo; pesare le dosi.","Portare acqua e saccarosio a 80 °C mescolando per formare uno sciroppo; aggiungere lo sciroppo di glucosio, mescolare fino a dissoluzione.","Raffreddare lo sciroppo a temperatura ambiente, poi a +4 °C.","Unire il succo di mandarino freddo allo sciroppo; aggiungere lo stabilizzante per freddo mescolando bene.","Maturare in frigorifero per 2-4 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere a −18 °C per almeno 2 ore."],"notaTecnica":"Il mandarino non è presente nella tabella zuccheri/altri solidi di gelato-reference.md §7 — valore stimato da fonti esterne convergenti (10-11g zuccheri/100g), marcato come tale in ingredienti.json. Stesso schema bilanciamento di Limone/Arancia."},{"id":"anguria","nome":"Sorbetto Anguria","categoria":"sorbetto","payoff":"Anguria estiva. Il sorbetto più leggero e acquoso del catalogo.","ingredienti":[{"id":"anguria-fresca","g_per_kg":485},{"id":"acqua","g_per_kg":185},{"id":"saccarosio","g_per_kg":110},{"id":"glucosio-42de","g_per_kg":90},{"id":"destrosio-monoidrato","g_per_kg":30},{"id":"stabilizzante","g_per_kg":5}],"ingredientiModificabili":[{"nome":"Anguria fresca","min":350,"max":560},{"nome":"Saccarosio","min":80,"max":145},{"nome":"Sciroppo di glucosio 42DE","min":65,"max":130}],"procedimento":["Pesare tutti gli ingredienti; usare anguria matura, privata dei semi.","Frullare la polpa di anguria fino a purea omogenea.","Portare acqua e saccarosio a 80 °C mescolando per formare uno sciroppo; aggiungere lo sciroppo di glucosio, mescolare fino a dissoluzione.","Raffreddare lo sciroppo a temperatura ambiente, poi a +4 °C.","Unire la purea di anguria fredda allo sciroppo; aggiungere lo stabilizzante per freddo mescolando bene.","Maturare in frigorifero per 2-4 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere a −18 °C per almeno 2 ore."],"notaTecnica":"L'anguria è il frutto con il più basso contenuto di zuccheri naturali del catalogo (6%, contro 9-20% degli altri): la quasi totalità della struttura zuccherina viene dagli zuccheri aggiunti. Stessa cautela del melone su catena del freddo, in assenza di acidità protettiva."},{"id":"pompelmo","nome":"Sorbetto Pompelmo","categoria":"sorbetto","payoff":"Pompelmo rosa, succo e polpa. Amarognolo, deciso, mai banale.","ingredienti":[{"id":"succo-pompelmo","g_per_kg":370},{"id":"acqua","g_per_kg":300},{"id":"saccarosio","g_per_kg":160},{"id":"glucosio-42de","g_per_kg":50},{"id":"destrosio-monoidrato","g_per_kg":15},{"id":"stabilizzante","g_per_kg":5}],"ingredientiModificabili":[{"nome":"Succo di pompelmo","min":260,"max":430},{"nome":"Saccarosio","min":115,"max":200},{"nome":"Sciroppo di glucosio 42DE","min":35,"max":75}],"procedimento":["Spremitura e filtratura del succo di pompelmo (preferibilmente rosa/rosso, meno amaro del bianco); pesare le dosi.","Portare acqua e saccarosio a 80 °C mescolando per formare uno sciroppo; aggiungere lo sciroppo di glucosio, mescolare fino a dissoluzione.","Raffreddare lo sciroppo a temperatura ambiente, poi a +4 °C.","Unire il succo di pompelmo freddo allo sciroppo; aggiungere lo stabilizzante per freddo mescolando bene.","Maturare in frigorifero per 2-4 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere a −18 °C per almeno 2 ore."],"notaTecnica":"Il pompelmo non è presente nella tabella zuccheri/altri solidi di gelato-reference.md §7 — valore stimato da fonti esterne convergenti (~7g zuccheri/100g, fonte USDA/Strongr Fastr/Dietabit), più basso di arancia e mandarino. La varietà rosa/rosso ha naringina in quantità minore della varietà bianca, risultando meno amara — preferibile per un sorbetto equilibrato. Stesso schema di bilanciamento di Limone/Arancia/Mandarino."},{"id":"cioccolato-vegano","nome":"Cioccolato Vegano","categoria":"vegano","payoff":"Cioccolato fondente, base cocco. Intenso, senza latticini.","ingredienti":[{"id":"latte-di-cocco-intero","g_per_kg":320},{"id":"acqua","g_per_kg":395},{"id":"cioccolato-fondente-copertura","g_per_kg":80},{"id":"inulina","g_per_kg":25},{"id":"stabilizzante","g_per_kg":5},{"id":"saccarosio","g_per_kg":30},{"id":"destrosio-monoidrato","g_per_kg":70},{"id":"glucosio-42de","g_per_kg":60}],"ingredientiModificabili":[{"nome":"Cioccolato fondente di copertura (70%)","min":50,"max":110},{"nome":"Latte di cocco intero","min":250,"max":450},{"nome":"Saccarosio","min":20,"max":120}],"eccezioniSoglie":["altri"],"procedimento":["Pesare tutti gli ingredienti; usare latte di cocco intero (non light).","Sciogliere il cioccolato fondente di copertura a bagnomaria (massimo 45 °C).","Mescolare a freddo saccarosio, destrosio, sciroppo di glucosio e inulina nel latte di cocco e nell'acqua.","Disperdere lo stabilizzante in una piccola quantità di zucchero e unire alla miscela.","Portare a 80 °C mescolando continuamente; mantenere per 20 secondi.","Togliere dal fuoco e incorporare subito il cioccolato fuso, mescolando bene per evitare grumi.","Raffreddare rapidamente a +4 °C.","Maturare in frigorifero per almeno 4 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere e conservare a −18 °C."],"notaTecnica":"Il latte di cocco intero (21% di grassi) sostituisce qui il ruolo di latte+panna delle creme tradizionali, fornendo il grasso necessario senza il quale, con basi vegetali più magre come avena o riso, i grassi resterebbero sotto il minimo del 5%. ECCEZIONE DOCUMENTATA: \\"Altri solidi\\" risulta sotto il range target (7-17%, qui ~4.9%) — stesso limite strutturale già documentato per Cocco Vegano: con gli ingredienti vegani disponibili e l'inulina alla dose di sicurezza, non è raggiungibile senza comprometterne la sicurezza/qualità."},{"id":"pistacchio-vegano","nome":"Pistacchio Vegano","categoria":"vegano","payoff":"Pasta di pistacchio pura, base riso. Vegetale, non stucchevole.","ingredienti":[{"id":"latte-di-riso","g_per_kg":560},{"id":"acqua","g_per_kg":120},{"id":"pasta-pistacchio-pura","g_per_kg":100},{"id":"inulina","g_per_kg":25},{"id":"stabilizzante","g_per_kg":5},{"id":"saccarosio","g_per_kg":50},{"id":"destrosio-monoidrato","g_per_kg":60},{"id":"glucosio-42de","g_per_kg":20}],"ingredientiModificabili":[{"nome":"Pasta di pistacchio pura","min":50,"max":110},{"nome":"Latte di riso","min":450,"max":650},{"nome":"Saccarosio","min":40,"max":110}],"eccezioniSoglie":["altri"],"procedimento":["Pesare tutti gli ingredienti; usare pasta di pistacchio pura (100% pistacchio, senza zuccheri aggiunti).","Mescolare a freddo saccarosio, destrosio, sciroppo di glucosio e inulina nel latte di riso e nell'acqua.","Disperdere lo stabilizzante in una piccola quantità di zucchero e unire alla miscela.","Portare a 80 °C mescolando continuamente; mantenere per 20 secondi.","Raffreddare rapidamente a +4 °C; incorporare la pasta di pistacchio a freddo mescolando con frusta fino a emulsione uniforme.","Maturare a 2-4 °C per almeno 4 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere e conservare a −18 °C."],"notaTecnica":"Il latte di riso, povero di grassi propri, lascia che il grasso della miscela derivi quasi interamente dalla pasta di pistacchio (55% di grassi vegetali) — coerente con come la versione non vegana usa la panna. ECCEZIONE DOCUMENTATA: \\"Altri solidi\\" leggermente sotto il range target (7-17%, qui ~6.5%) — stesso limite strutturale già documentato per Cocco Vegano."},{"id":"nocciola-vegano","nome":"Nocciola Vegano","categoria":"vegano","payoff":"Pasta di nocciola pura, base avena. Vegetale, tostato.","ingredienti":[{"id":"latte-di-avena","g_per_kg":560},{"id":"acqua","g_per_kg":90},{"id":"pasta-nocciola-pura","g_per_kg":120},{"id":"inulina","g_per_kg":25},{"id":"stabilizzante","g_per_kg":5},{"id":"saccarosio","g_per_kg":80},{"id":"destrosio-monoidrato","g_per_kg":60},{"id":"glucosio-42de","g_per_kg":25}],"ingredientiModificabili":[{"nome":"Pasta di nocciola pura","min":80,"max":160},{"nome":"Latte di avena","min":450,"max":650},{"nome":"Saccarosio","min":70,"max":140}],"procedimento":["Pesare tutti gli ingredienti; usare pasta di nocciola pura (100% nocciola, senza zuccheri aggiunti).","Mescolare a freddo saccarosio, destrosio, sciroppo di glucosio e inulina nel latte di avena e nell'acqua.","Disperdere lo stabilizzante in una piccola quantità di zucchero e unire alla miscela.","Portare a 80 °C mescolando continuamente; mantenere per 20 secondi.","Raffreddare rapidamente a +4 °C; incorporare la pasta di nocciola a freddo mescolando con frusta fino a emulsione uniforme.","Maturare a 2-4 °C per almeno 4 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere e conservare a −18 °C."],"notaTecnica":"Unica delle 4 ricette vegane di questo gruppo a non richiedere l'eccezione su \\"altri solidi\\": la pasta di nocciola, più ricca in proteine vegetali della pasta di pistacchio, porta da sola il parametro dentro il range 7-17% senza bisogno di forzare l'inulina. Stesso schema di bilanciamento delle altre creme vegane a frutta secca."},{"id":"matcha-vegano","nome":"Matcha Vegano","categoria":"vegano","payoff":"Tè matcha giapponese, base cocco. Verde, vegetale, vivace.","ingredienti":[{"id":"latte-di-cocco-intero","g_per_kg":400},{"id":"acqua","g_per_kg":345},{"id":"matcha-polvere","g_per_kg":15},{"id":"inulina","g_per_kg":25},{"id":"stabilizzante","g_per_kg":5},{"id":"saccarosio","g_per_kg":75},{"id":"destrosio-monoidrato","g_per_kg":85},{"id":"glucosio-42de","g_per_kg":20}],"ingredientiModificabili":[{"nome":"Tè matcha in polvere","min":10,"max":25},{"nome":"Latte di cocco intero","min":270,"max":470},{"nome":"Saccarosio","min":70,"max":160}],"eccezioniSoglie":["altri"],"procedimento":["Pesare tutti gli ingredienti; setacciare il tè matcha per eliminare eventuali grumi prima dell'uso.","Mescolare a freddo saccarosio, destrosio, sciroppo di glucosio e inulina nel latte di cocco e nell'acqua.","Stemperare il matcha setacciato in una piccola quantità di liquido tiepido fino a ottenere una crema senza grumi, poi unirla al resto.","Disperdere lo stabilizzante in una piccola quantità di zucchero e unire alla miscela.","Portare a 80 °C mescolando continuamente; mantenere per 20 secondi (non superare gli 80 °C: il calore eccessivo altera il colore e l'aroma del matcha).","Raffreddare rapidamente a +4 °C.","Maturare in frigorifero per almeno 4 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere e conservare a −18 °C."],"notaTecnica":"Il matcha si scioglie male a freddo se non setacciato e stemperato con cura: i grumi non si disperdono più una volta nella miscela completa. Il latte di cocco fornisce il grasso necessario (il matcha stesso ne contiene pochissimo, e solo in dose minima). ECCEZIONE DOCUMENTATA: \\"Altri solidi\\" sotto il range target (7-17%, qui ~4.2%) — stesso limite strutturale di Cocco Vegano e Cioccolato Vegano."},{"id":"crema","nome":"Crema","categoria":"crema","payoff":"Vaniglia e tuorli. La base classica della pasticceria, in gelato.","ingredienti":[{"id":"latte-intero","g_per_kg":510},{"id":"panna-35","g_per_kg":130},{"id":"tuorlo-uovo","g_per_kg":60},{"id":"saccarosio","g_per_kg":95},{"id":"latte-polvere-scremato","g_per_kg":50},{"id":"destrosio-monoidrato","g_per_kg":65},{"id":"glucosio-42de","g_per_kg":35},{"id":"estratto-vaniglia","g_per_kg":8},{"id":"stabilizzante","g_per_kg":8}],"ingredientiModificabili":[{"nome":"Tuorlo d'uovo (pastorizzato)","min":35,"max":95},{"nome":"Panna 35%","min":85,"max":180},{"nome":"Saccarosio","min":65,"max":135}],"procedimento":["Pesare tutti gli ingredienti. Usare tuorli pastorizzati (in brick) oppure pastorizzare personalmente le uova fresche: passaggio di sicurezza alimentare obbligatorio per eliminare il rischio Salmonella.","Sciogliere il latte in polvere scremato nel latte intero a temperatura ambiente.","Sbattere i tuorli con una parte del saccarosio fino a renderli chiari e spumosi.","Unire il composto di tuorli al latte insieme alla panna, al resto del saccarosio, al destrosio e allo sciroppo di glucosio; disperdere lo stabilizzante in una piccola quantità di zucchero e unire.","Portare la miscela a 85 °C e mantenere per almeno 15 secondi — con i tuorli, non superare gli 85 °C per evitare la coagulazione (effetto \\"frittata\\").","Raffreddare rapidamente a +4 °C; aggiungere l'estratto di vaniglia a freddo, mescolando bene.","Maturare in frigorifero per almeno 4 ore.","Mantecare fino a estrazione a −7/−9 °C al cuore.","Abbattere e conservare a −18 °C."],"notaTecnica":"La \\"Crema\\" classica si distingue da Fior di Panna per la presenza dei tuorli (che danno corpo e colore dorato) e da Zabaione per l'assenza di Marsala/alcol — qui l'aromatizzazione è solo vaniglia. I tuorli vengono dosati a circa metà della quantità usata in Zabaione, dove sono l'ingrediente caratterizzante principale invece che un coadiuvante di struttura. Stessa attenzione alla pastorizzazione (sicurezza alimentare con le uova) già documentata per Zabaione."}]`),c=o(`ricette`,()=>{let e=t(s),r=t(null),i=n(()=>r.value?e.value.filter(e=>e.categoria===r.value):e.value);function a(t){return e.value.find(e=>e.id===t)??null}function o(e){r.value=e===r.value?null:e}return{ricette:e,filtroCategoria:r,ricetteFiltrate:i,getRicettaById:a,setFiltro:o}}),l={__name:`BadgeCategoria`,props:{categoria:{type:String,required:!0}},setup(t){let n={crema:{bg:`bg-turchese`,text:`text-bianco`},frutta:{bg:`bg-fucsia`,text:`text-bianco`},sorbetto:{bg:`bg-indaco`,text:`text-bianco`},vegano:{bg:`bg-bruciato`,text:`text-bianco`}};return(o,s)=>(e(),i(`span`,{class:a([`inline-flex items-center px-2.5 py-0.5 rounded-full text-ui-label`,[n[t.categoria]?.bg??`bg-indaco`,n[t.categoria]?.text??`text-bianco`]])},r(t.categoria),3))}};export{c as n,l as t};